import * as SQLite from "expo-sqlite";

let db = null;

// Initialize Database Concept
export const openDatabase = async () => {
  try {
    if (db !== null) {
      return db;
    }
    db = await SQLite.openDatabaseAsync("smart_study_planner.db");
    return db;
  } catch (error) {
    console.warn("Re-initializing DB due to null reference:", error);
    db = await SQLite.openDatabaseAsync("smart_study_planner.db");
    return db;
  }
};

// Initialize Tables
export const initDatabase = async () => {
  try {
    const database = await openDatabase();

    // Create Tables
    await database.execAsync(`
      PRAGMA foreign_keys = ON;

      CREATE TABLE IF NOT EXISTS courses (
        id INTEGER PRIMARY KEY AUTOINCREMENT,
        course_name TEXT NOT NULL,
        credits INTEGER DEFAULT 0,
        lecturer_name TEXT,
        semester INTEGER,
        absent_count INTEGER DEFAULT 0,
        max_absences INTEGER DEFAULT 3
      );

      CREATE TABLE IF NOT EXISTS study_plans (
        id INTEGER PRIMARY KEY AUTOINCREMENT,
        course_id INTEGER,
        day_of_week TEXT,
        start_time TEXT,
        end_time TEXT,
        priority TEXT,
        notes TEXT,
        FOREIGN KEY(course_id) REFERENCES courses(id) ON DELETE CASCADE
      );

      CREATE TABLE IF NOT EXISTS tasks (
        id INTEGER PRIMARY KEY AUTOINCREMENT,
        course_id INTEGER,
        task_name TEXT NOT NULL,
        description TEXT,
        deadline TEXT,
        priority TEXT,
        status TEXT DEFAULT 'Belum Dikerjakan',
        FOREIGN KEY(course_id) REFERENCES courses(id) ON DELETE CASCADE
      );

      CREATE TABLE IF NOT EXISTS class_schedules (
        id INTEGER PRIMARY KEY AUTOINCREMENT,
        course_id INTEGER,
        day_of_week TEXT,
        start_time TEXT,
        end_time TEXT,
        room TEXT,
        building TEXT,
        class_type TEXT,
        notes TEXT,
        is_active INTEGER DEFAULT 1,
        FOREIGN KEY(course_id) REFERENCES courses(id) ON DELETE CASCADE
      );

      CREATE TABLE IF NOT EXISTS course_notes (
        id INTEGER PRIMARY KEY AUTOINCREMENT,
        course_id INTEGER,
        title TEXT NOT NULL,
        content TEXT,
        FOREIGN KEY(course_id) REFERENCES courses(id) ON DELETE CASCADE
      );
    `);

    // Migrasi bagi database lama yang belum memiliki kolom absensi
    try {
      await database.execAsync(`
        ALTER TABLE courses ADD COLUMN absent_count INTEGER DEFAULT 0;
      `);
    } catch (e) {
      // Abaikan bila kolom sudah ada
    }

    try {
      await database.execAsync(`
        ALTER TABLE courses ADD COLUMN max_absences INTEGER DEFAULT 3;
      `);
    } catch (e) {
      // Abaikan bila kolom sudah ada
    }

    console.log("Database initialized successfully.");
  } catch (error) {
    console.error("Error initializing database: ", error);
  }
};

// ========================
// REUSABLE CRUD HELPERS
// ========================

export const fetchAll = async (query, parameters = []) => {
  try {
    const database = await openDatabase();
    const result = await database.getAllAsync(query, parameters);
    return result;
  } catch (error) {
    console.error("Error fetching data: ", error);
    return [];
  }
};

export const fetchOne = async (query, parameters = []) => {
  try {
    const database = await openDatabase();
    const result = await database.getFirstAsync(query, parameters);
    return result;
  } catch (error) {
    console.error("Error fetching single data: ", error);
    return null;
  }
};

export const executeWrite = async (query, parameters = []) => {
  try {
    const database = await openDatabase();
    const result = await database.runAsync(query, parameters);
    return result; // contains { changes, lastInsertRowId }
  } catch (error) {
    console.error("Error writing data: ", error);
    return null;
  }
};

import React from "react";
import { View, TouchableOpacity, Text, Platform } from "react-native";
import { createBottomTabNavigator } from "@react-navigation/bottom-tabs";
import { createNativeStackNavigator } from "@react-navigation/native-stack";
import { Ionicons } from "@expo/vector-icons";
import { useSafeAreaInsets } from "react-native-safe-area-context";
import { useColorScheme } from "react-native";
// Import Screens
import DashboardScreen from "../screens/DashboardScreen";
import CoursesScreen from "../screens/CoursesScreen";
import TasksScreen from "../screens/TasksScreen";
import SchedulesScreen from "../screens/SchedulesScreen";
import NotesScreen from "../screens/NotesScreen";

const Tab = createBottomTabNavigator();
const Stack = createNativeStackNavigator();

const CustomTabBarButton = ({ children, onPress }) => (
  <TouchableOpacity
    style={{
      top: -20,
      justifyContent: "center",
      alignItems: "center",
      shadowColor: "#3b82f6",
      shadowOpacity: 0.3,
      shadowRadius: 10,
      shadowOffset: { width: 0, height: 5 },
    }}
    onPress={onPress}
  >
    <View
      style={{
        width: 60,
        height: 60,
        borderRadius: 30,
        backgroundColor: "#6366f1", // indigo-500
        justifyContent: "center",
        alignItems: "center",
        borderWidth: 4,
        borderColor: "#f8fafc", // slate-50
      }}
    >
      {children}
    </View>
    <Text
      style={{
        fontSize: 10,
        color: "#6366f1",
        fontWeight: "bold",
        marginTop: 4,
      }}
    >
      Catatan
    </Text>
  </TouchableOpacity>
);

// Tab Navigator for main screens
function BottomTabNavigator() {
  const insets = useSafeAreaInsets();
  const colorScheme = useColorScheme();
  const isDark = colorScheme === "dark";

  return (
    <Tab.Navigator
      screenOptions={({ route }) => ({
        headerShown: false,
        tabBarIcon: ({ focused, color, size }) => {
          let iconName;
          if (route.name === "Dashboard") {
            iconName = focused ? "grid" : "grid-outline";
          } else if (route.name === "Mata Kuliah") {
            iconName = focused ? "book" : "book-outline";
          } else if (route.name === "Catatan") {
            return <Ionicons name="add" size={32} color="#fff" />;
          } else if (route.name === "Tugas") {
            iconName = focused
              ? "checkmark-circle"
              : "checkmark-circle-outline";
          } else if (route.name === "Jadwal") {
            iconName = focused ? "calendar" : "calendar-outline";
          }
          return <Ionicons name={iconName} size={24} color={color} />;
        },
        tabBarActiveTintColor: isDark ? "#818CF8" : "#4F46E5", // indigo-400 : indigo-600
        tabBarInactiveTintColor: isDark ? "#64748B" : "#94A3B8", // slate-500 : slate-400
        tabBarStyle: {
          position: "absolute",
          bottom: Platform.OS === "android" ? 15 : 25,
          left: 20,
          right: 20,
          elevation: 0,
          backgroundColor: isDark ? "#1E293B" : "#FFFFFF",
          borderRadius: 24,
          height: 70,
          paddingBottom: 10,
          paddingTop: 10,
          shadowColor: isDark ? "#000" : "#94A3B8",
          shadowOffset: {
            width: 0,
            height: 10,
          },
          shadowOpacity: isDark ? 0.5 : 0.1,
          shadowRadius: 15,
          borderTopWidth: 0,
        },
        tabBarLabelStyle: {
          fontSize: 10,
          fontWeight: "bold",
          marginTop: 2,
        },
      })}
    >
      <Tab.Screen
        name="Dashboard"
        component={DashboardScreen}
        options={{ tabBarLabel: "Home" }}
      />
      <Tab.Screen
        name="Mata Kuliah"
        component={CoursesScreen}
        options={{ tabBarLabel: "Matkul" }}
      />
      <Tab.Screen
        name="Catatan"
        component={NotesScreen}
        options={{
          tabBarButton: (props) => <CustomTabBarButton {...props} />,
          tabBarLabel: () => null,
        }}
      />
      <Tab.Screen name="Tugas" component={TasksScreen} />
      <Tab.Screen name="Jadwal" component={SchedulesScreen} />
    </Tab.Navigator>
  );
}

// Main App Stack Navigator
export default function AppNavigator() {
  return (
    <Stack.Navigator screenOptions={{ headerShown: false }}>
      <Stack.Screen name="Main" component={BottomTabNavigator} />
    </Stack.Navigator>
  );
}

import React, { useState, useCallback } from "react";
import {
  View,
  Text,
  TouchableOpacity,
  FlatList,
  TextInput,
  Modal,
  Alert,
  KeyboardAvoidingView,
  Platform,
  ScrollView,
} from "react-native";
import { SafeAreaView } from "react-native-safe-area-context";
import { Ionicons } from "@expo/vector-icons";
import { useFocusEffect } from "@react-navigation/native";
import { fetchAll, executeWrite } from "../database/dbHelper";
import { useColorScheme } from "react-native";
import InteractiveCard from "../components/InteractiveCard";

export default function CoursesScreen() {
  const [courses, setCourses] = useState([]);
  const [isModalVisible, setModalVisible] = useState(false);
  const [editingCourse, setEditingCourse] = useState(null);
  const [searchQuery, setSearchQuery] = useState("");

  const colorScheme = useColorScheme();
  const isDark = colorScheme === "dark";

  // Form State
  const [courseName, setCourseName] = useState("");
  const [credits, setCredits] = useState("");
  const [lecturer, setLecturer] = useState("");
  const [semester, setSemester] = useState("");
  const [maxAbsences, setMaxAbsences] = useState("3");

  const updateAbsence = async (id, currentCount, max, increment) => {
    let newCount = currentCount;
    if (increment && currentCount < max) newCount++;
    else if (!increment && currentCount > 0) newCount--;

    if (newCount !== currentCount) {
      await executeWrite("UPDATE courses SET absent_count = ? WHERE id = ?", [
        newCount,
        id,
      ]);
      setTimeout(() => {
        loadCourses();
      }, 100);
    }
  };

  const loadCourses = async () => {
    try {
      const data = await fetchAll(
        "SELECT * FROM courses ORDER BY course_name ASC",
      );
      setCourses(data);
    } catch (error) {
      console.error("Failed to load courses:", error);
    }
  };

  useFocusEffect(
    useCallback(() => {
      loadCourses();
    }, []),
  );

  const openAddModal = () => {
    setEditingCourse(null);
    setCourseName("");
    setCredits("");
    setLecturer("");
    setSemester("");
    setMaxAbsences("3");
    setModalVisible(true);
  };

  const openEditModal = (course) => {
    setEditingCourse(course);
    setCourseName(course.course_name);
    setCredits(course.credits ? course.credits.toString() : "");
    setLecturer(course.lecturer_name || "");
    setSemester(course.semester ? course.semester.toString() : "");
    setMaxAbsences(course.max_absences ? course.max_absences.toString() : "3");
    setModalVisible(true);
  };

  const saveCourse = async () => {
    if (!courseName.trim()) {
      Alert.alert("Error", "Nama mata kuliah tidak boleh kosong");
      return;
    }

    try {
      if (editingCourse) {
        // Update
        await executeWrite(
          "UPDATE courses SET course_name = ?, credits = ?, lecturer_name = ?, semester = ?, max_absences = ? WHERE id = ?",
          [
            courseName,
            parseInt(credits) || 0,
            lecturer,
            parseInt(semester) || 0,
            parseInt(maxAbsences) || 3,
            editingCourse.id,
          ],
        );
      } else {
        // Insert
        await executeWrite(
          "INSERT INTO courses (course_name, credits, lecturer_name, semester, max_absences) VALUES (?, ?, ?, ?, ?)",
          [
            courseName,
            parseInt(credits) || 0,
            lecturer,
            parseInt(semester) || 0,
            parseInt(maxAbsences) || 3,
          ],
        );
      }
      setModalVisible(false);
      setTimeout(() => {
        loadCourses();
      }, 100);
    } catch (error) {
      console.error("Failed to save course:", error);
      Alert.alert("Error", "Gagal menyimpan mata kuliah");
    }
  };

  const confirmDelete = (id) => {
    Alert.alert(
      "Hapus Mata Kuliah",
      "Apakah Anda yakin? Semua tugas dan jadwal terkait mata kuliah ini juga akan terhapus.",
      [
        { text: "Batal", style: "cancel" },
        {
          text: "Hapus",
          style: "destructive",
          onPress: async () => {
            await executeWrite("DELETE FROM courses WHERE id = ?", [id]);
            setTimeout(() => {
              loadCourses();
            }, 100);
          },
        },
      ],
    );
  };

  const renderCourseItem = ({ item }) => {
    const iconStyle = [
      { bgDark: "rgba(30, 58, 138, 0.3)", bgLight: "#dbeafe" }, // blue
      { bgDark: "rgba(88, 28, 135, 0.3)", bgLight: "#f3e8ff" }, // purple
      { bgDark: "rgba(6, 78, 59, 0.3)", bgLight: "#d1fae5" }, // emerald
      { bgDark: "rgba(124, 45, 18, 0.3)", bgLight: "#ffedd5" }, // orange
    ];
    const colorHex = ["#3B82F6", "#A855F7", "#10B981", "#F97316"];
    const icons = [
      "book",
      "cloud-outline",
      "grid-outline",
      "shield-half-outline",
    ];
    const idx = (item.id || 0) % 4;

    return (
      <View className="mb-4 px-5">
        <InteractiveCard>
          <View className="bg-white dark:bg-slate-800 rounded-[28px] p-5 shadow-sm shadow-slate-200/50 dark:shadow-none border border-slate-100 dark:border-slate-700">
            <View className="flex-row justify-between items-center mb-4">
              <View
                className="w-12 h-12 rounded-2xl items-center justify-center"
                style={{
                  backgroundColor: isDark
                    ? iconStyle[idx].bgDark
                    : iconStyle[idx].bgLight,
                }}
              >
                <Ionicons
                  name={icons[idx]}
                  size={24}
                  color={isDark ? colorHex[idx] : colorHex[idx]}
                />
              </View>
              <View className="bg-slate-100 dark:bg-slate-700/50 px-3 py-1.5 rounded-full border border-slate-200 dark:border-slate-600">
                <Text className="text-slate-600 dark:text-slate-300 font-bold text-xs">
                  {item.credits} SKS
                </Text>
              </View>
            </View>

            <Text className="text-xl font-bold font-serif text-slate-800 dark:text-white mb-4">
              {item.course_name}
            </Text>

            <View className="flex-row items-center mb-2">
              <View className="w-6 items-center">
                <Ionicons name="person" size={14} color="#64748B" />
              </View>
              <Text className="text-slate-500 dark:text-slate-400 text-sm font-medium">
                {item.lecturer_name || "Tanpa Dosen"}
              </Text>
            </View>
            <View className="flex-row items-center mb-5">
              <View className="w-6 items-center">
                <Ionicons name="calendar" size={14} color="#64748B" />
              </View>
              <Text className="text-slate-500 dark:text-slate-400 text-sm font-medium">
                Semester {item.semester}
              </Text>
            </View>

            {/* Attendance Tracker Bar */}
            <View className="mb-5 bg-slate-50 dark:bg-slate-700/50 p-4 rounded-2xl border border-slate-100 dark:border-slate-600">
              <View className="flex-row justify-between items-center mb-3">
                <View>
                  <Text className="text-slate-700 dark:text-slate-300 font-bold text-[13px] uppercase tracking-wider mb-1">
                    Jatah Bolos
                  </Text>
                  <Text className="text-slate-500 dark:text-slate-400 text-xs">
                    {(item.max_absences || 3) - (item.absent_count || 0)} sisa
                    slot libur
                  </Text>
                </View>
                <View className="flex-row items-center bg-white dark:bg-slate-800 rounded-full border border-slate-200 dark:border-slate-700 p-1 shadow-sm">
                  <TouchableOpacity
                    onPress={() =>
                      updateAbsence(
                        item.id,
                        item.absent_count || 0,
                        item.max_absences || 3,
                        false,
                      )
                    }
                    className="w-8 h-8 rounded-full bg-slate-50 dark:bg-slate-700 items-center justify-center active:bg-slate-200 dark:active:bg-slate-600"
                  >
                    <Ionicons
                      name="remove"
                      size={16}
                      color={isDark ? "#E2E8F0" : "#475569"}
                    />
                  </TouchableOpacity>
                  <View className="mx-2 items-center min-w-[30px]">
                    <Text className="text-lg font-bold text-slate-800 dark:text-white leading-none">
                      {item.absent_count || 0}
                    </Text>
                  </View>
                  <TouchableOpacity
                    onPress={() =>
                      updateAbsence(
                        item.id,
                        item.absent_count || 0,
                        item.max_absences || 3,
                        true,
                      )
                    }
                    className="w-8 h-8 rounded-full bg-slate-50 dark:bg-slate-700 items-center justify-center active:bg-slate-200 dark:active:bg-slate-600"
                  >
                    <Ionicons
                      name="add"
                      size={16}
                      color={isDark ? "#E2E8F0" : "#475569"}
                    />
                  </TouchableOpacity>
                </View>
              </View>

              {/* Progress Bar Container */}
              <View className="h-2 w-full bg-slate-200 dark:bg-slate-600/50 rounded-full overflow-hidden">
                <View
                  style={{
                    width: `${Math.min(((item.absent_count || 0) / (item.max_absences || 3)) * 100, 100)}%`,
                  }}
                  className={`h-full rounded-full ${(item.absent_count || 0) >= (item.max_absences || 3) ? "bg-rose-500" : (item.absent_count || 0) >= (item.max_absences || 3) - 1 ? "bg-amber-400" : "bg-emerald-500"}`}
                />
              </View>
            </View>

            <View className="flex-row justify-between gap-3 pt-3 border-t border-slate-100 dark:border-slate-700/50">
              <TouchableOpacity
                onPress={() => openEditModal(item)}
                className="flex-1 bg-slate-50 dark:bg-slate-700/50 rounded-2xl py-3 flex-row items-center justify-center border border-slate-100 dark:border-slate-600"
              >
                <Ionicons
                  name="pencil"
                  size={16}
                  color={isDark ? "#CBD5E1" : "#475569"}
                />
                <Text className="text-slate-600 dark:text-slate-300 font-bold ml-2 text-sm">
                  Edit
                </Text>
              </TouchableOpacity>
              <TouchableOpacity
                onPress={() => confirmDelete(item.id)}
                className="flex-1 bg-rose-50 dark:bg-rose-500/10 rounded-2xl py-3 flex-row items-center justify-center border border-rose-100 dark:border-rose-500/20"
              >
                <Ionicons name="trash" size={16} color="#F43F5E" />
                <Text className="text-rose-500 font-bold ml-2 text-sm">
                  Hapus
                </Text>
              </TouchableOpacity>
            </View>
          </View>
        </InteractiveCard>
      </View>
    );
  };

  const renderHeader = () => (
    <>
      {/* Header SmartStudy top */}
      <View className="px-6 pt-6 pb-2 flex-row justify-between items-center mb-2">
        <View className="flex-row items-center">
          <View className="w-10 h-10 bg-indigo-100 dark:bg-indigo-900/50 rounded-2xl items-center justify-center mr-3">
            <Ionicons name="school" size={20} color="#4F46E5" />
          </View>
          <Text className="text-xl font-bold tracking-tight text-slate-800 dark:text-slate-100">
            SmartStudy
          </Text>
        </View>
      </View>

      <View className="px-5 mb-4 mt-2 flex-row justify-between items-end">
        <View className="flex-1 pr-2">
          <Text className="text-sm font-semibold text-emerald-500 dark:text-emerald-400 mb-1 tracking-widest uppercase">
            Kurikulum
          </Text>
          <Text className="text-3xl font-serif font-bold text-[#1a365d] dark:text-white mb-2 tracking-tight">
            Mata Kuliah
          </Text>
          <Text className="text-slate-500 dark:text-slate-400 text-sm">
            Kelola daftar mata kuliah yang Anda ambil.
          </Text>
        </View>
      </View>

      <View className="px-5 mb-6">
        <InteractiveCard onPress={openAddModal}>
          <View className="bg-emerald-500 dark:bg-emerald-600 rounded-[20px] py-3 flex-row items-center justify-center shadow-md shadow-emerald-500/20">
            <Ionicons name="add-circle" size={22} color="white" />
            <Text className="text-white font-bold text-[15px] ml-2 tracking-wide">
              Mata Kuliah Baru
            </Text>
          </View>
        </InteractiveCard>
      </View>

      {/* Search Bar */}
      <View className="px-5 mb-4">
        <View className="bg-white dark:bg-slate-800 flex-row items-center px-4 py-2 rounded-[16px] border border-slate-100 dark:border-slate-700 shadow-sm shadow-slate-200/50 dark:shadow-none">
          <Ionicons name="search" size={18} color="#94A3B8" />
          <TextInput
            className="flex-1 ml-2 text-slate-800 dark:text-white text-[14px] font-medium"
            placeholder="Cari mata kuliah..."
            placeholderTextColor="#94A3B8"
            value={searchQuery}
            onChangeText={setSearchQuery}
          />
        </View>
      </View>
    </>
  );

  return (
    <SafeAreaView
      className="flex-1 bg-slate-50 dark:bg-[#0F172A]"
      edges={["top"]}
    >
      <FlatList
        data={courses.filter((c) =>
          c.course_name.toLowerCase().includes(searchQuery.toLowerCase()),
        )}
        keyExtractor={(item) => item.id.toString()}
        renderItem={renderCourseItem}
        ListHeaderComponent={renderHeader}
        contentContainerStyle={{
          paddingBottom: 160,
        }}
        showsVerticalScrollIndicator={false}
        ListEmptyComponent={
          courses.length > 0 ? (
            <View className="py-20 flex items-center justify-center">
              <Text className="text-slate-500 dark:text-slate-400">
                Tidak ada hasil pencarian.
              </Text>
            </View>
          ) : (
            <View className="py-20 flex items-center justify-center">
              <Ionicons
                name="library-outline"
                size={80}
                color={isDark ? "#334155" : "#CBD5E1"}
                className="mb-4"
              />
              <Text className="text-slate-800 dark:text-white text-lg font-bold">
                Data Kosong
              </Text>
              <Text className="text-slate-500 dark:text-slate-400 text-center mt-2 max-w-[250px]">
                Ketuk tombol + di atas untuk menambahkan mata kuliah pertama
                Anda.
              </Text>
            </View>
          )
        }
      />

      {/* Modal Add/Edit */}
      <Modal visible={isModalVisible} animationType="slide" transparent={true}>
        <View className="flex-1 justify-end bg-slate-900/60">
          <KeyboardAvoidingView
            behavior={Platform.OS === "ios" ? "padding" : "height"}
            className="bg-white dark:bg-[#0F172A] rounded-t-3xl pt-2 pb-8 px-6 h-[80%]"
          >
            {/* Handle Bar */}
            <View className="items-center mb-6">
              <View className="w-12 h-1.5 bg-slate-200 dark:bg-slate-700 rounded-full mt-2" />
            </View>

            <View className="flex-row justify-between items-center mb-6">
              <Text className="text-xl font-bold text-slate-800 dark:text-white">
                {editingCourse ? "Edit Mata Kuliah" : "Tambah Mata Kuliah"}
              </Text>
              <TouchableOpacity
                onPress={() => setModalVisible(false)}
                className="bg-slate-100 dark:bg-slate-800 p-2 rounded-full"
              >
                <Ionicons name="close" size={24} color="#94A3B8" />
              </TouchableOpacity>
            </View>

            <ScrollView
              showsVerticalScrollIndicator={false}
              contentContainerStyle={{ paddingBottom: 100 }}
              keyboardShouldPersistTaps="handled"
            >
              <Text className="text-sm font-semibold text-slate-700 dark:text-slate-300 mb-2 mt-2">
                Nama Mata Kuliah *
              </Text>
              <TextInput
                className="bg-slate-50 dark:bg-[#1E293B] border border-slate-200 dark:border-slate-800 rounded-2xl px-4 py-4 text-slate-800 dark:text-white mb-6"
                placeholder="Contoh: Pemrograman Mobile"
                placeholderTextColor={isDark ? "#64748B" : "#94A3B8"}
                value={courseName}
                onChangeText={setCourseName}
              />
              <View className="flex-row justify-between">
                <View className="w-[48%]">
                  <Text className="text-sm font-semibold text-slate-700 dark:text-slate-300 mb-2">
                    SKS
                  </Text>
                  <TextInput
                    className="bg-slate-50 dark:bg-[#1E293B] border border-slate-200 dark:border-slate-800 rounded-2xl px-4 py-4 text-slate-800 dark:text-white mb-6"
                    placeholder="Contoh: 3"
                    placeholderTextColor={isDark ? "#64748B" : "#94A3B8"}
                    keyboardType="numeric"
                    value={credits}
                    onChangeText={setCredits}
                  />
                </View>
                <View className="w-[48%]">
                  <Text className="text-sm font-semibold text-slate-700 dark:text-slate-300 mb-2">
                    Semester
                  </Text>
                  <TextInput
                    className="bg-slate-50 dark:bg-[#1E293B] border border-slate-200 dark:border-slate-800 rounded-2xl px-4 py-4 text-slate-800 dark:text-white mb-6"
                    placeholder="Contoh: 5"
                    placeholderTextColor={isDark ? "#64748B" : "#94A3B8"}
                    keyboardType="numeric"
                    value={semester}
                    onChangeText={setSemester}
                  />
                </View>
              </View>
              <Text className="text-sm font-semibold text-slate-700 dark:text-slate-300 mb-2">
                Nama Dosen
              </Text>
              <TextInput
                className="bg-slate-50 dark:bg-[#1E293B] border border-slate-200 dark:border-slate-800 rounded-2xl px-4 py-4 text-slate-800 dark:text-white mb-6"
                placeholder="Contoh: Budi Santoso, M.Kom"
                placeholderTextColor={isDark ? "#64748B" : "#94A3B8"}
                value={lecturer}
                onChangeText={setLecturer}
              />
              <Text className="text-sm font-semibold text-slate-700 dark:text-slate-300 mb-2">
                Batas Jatah Bolos (Max Absen)
              </Text>
              <TextInput
                className="bg-slate-50 dark:bg-[#1E293B] border border-slate-200 dark:border-slate-800 rounded-2xl px-4 py-4 text-slate-800 dark:text-white mb-8"
                placeholder="Contoh: 3"
                placeholderTextColor={isDark ? "#64748B" : "#94A3B8"}
                keyboardType="numeric"
                value={maxAbsences}
                onChangeText={setMaxAbsences}
              />
              <TouchableOpacity
                onPress={saveCourse}
                className="bg-blue-500 rounded-2xl py-4 items-center shadow-lg shadow-blue-500/30 dark:shadow-none"
              >
                <Text className="text-white font-bold text-base">
                  Simpan Data
                </Text>
              </TouchableOpacity>
            </ScrollView>
          </KeyboardAvoidingView>
        </View>
      </Modal>
    </SafeAreaView>
  );
}

import React, { useState, useCallback } from "react";
import {
  View,
  Text,
  TouchableOpacity,
  FlatList,
  TextInput,
  Modal,
  Alert,
  KeyboardAvoidingView,
  Platform,
  ScrollView,
} from "react-native";
import { SafeAreaView } from "react-native-safe-area-context";
import { Ionicons } from "@expo/vector-icons";
import { useFocusEffect } from "@react-navigation/native";
import { fetchAll, executeWrite } from "../database/dbHelper";
import { useColorScheme } from "react-native";
import InteractiveCard from "../components/InteractiveCard";

export default function NotesScreen() {
  const [notes, setNotes] = useState([]);
  const [courses, setCourses] = useState([]);
  const [isModalVisible, setModalVisible] = useState(false);
  const [editingNote, setEditingNote] = useState(null);
  const colorScheme = useColorScheme();
  const isDark = colorScheme === "dark";

  // Filter States
  const [searchQuery, setSearchQuery] = useState("");
  const filterChips = ["Semua", "Semester 6", "Tugas Akhir", "Umum"];
  const [activeChip, setActiveChip] = useState("Semua");

  // Form State
  const [title, setTitle] = useState("");
  const [content, setContent] = useState("");
  const [courseId, setCourseId] = useState("");

  const loadData = async () => {
    try {
      const notesData = await fetchAll(`
        SELECT n.*, c.course_name 
        FROM course_notes n 
        LEFT JOIN courses c ON n.course_id = c.id 
        ORDER BY n.id DESC
      `);
      setNotes(notesData);

      const coursesData = await fetchAll(
        "SELECT id, course_name FROM courses ORDER BY course_name ASC",
      );
      setCourses(coursesData);
    } catch (error) {
      console.error("Failed to load notes:", error);
    }
  };

  useFocusEffect(
    useCallback(() => {
      loadData();
    }, []),
  );

  const openAddModal = () => {
    setEditingNote(null);
    setTitle("");
    setContent("");
    setCourseId("");
    setModalVisible(true);
  };

  const openEditModal = (note) => {
    setEditingNote(note);
    setTitle(note.title);
    setContent(note.content || "");
    setCourseId(note.course_id || "");
    setModalVisible(true);
  };

  const saveNote = async () => {
    if (!title.trim()) {
      Alert.alert("Error", "Judul catatan tidak boleh kosong");
      return;
    }

    try {
      if (editingNote) {
        await executeWrite(
          "UPDATE course_notes SET course_id = ?, title = ?, content = ? WHERE id = ?",
          [courseId || null, title, content, editingNote.id],
        );
      } else {
        await executeWrite(
          "INSERT INTO course_notes (course_id, title, content) VALUES (?, ?, ?)",
          [courseId || null, title, content],
        );
      }
      setModalVisible(false);
      setTimeout(() => {
        loadData();
      }, 100);
    } catch (error) {
      console.error("Failed to save note:", error);
      Alert.alert("Error", "Gagal menyimpan catatan");
    }
  };

  const confirmDelete = (id) => {
    Alert.alert("Hapus Catatan", "Apakah Anda yakin?", [
      { text: "Batal", style: "cancel" },
      {
        text: "Hapus",
        style: "destructive",
        onPress: async () => {
          await executeWrite("DELETE FROM course_notes WHERE id = ?", [id]);
          setTimeout(() => {
            loadData();
          }, 100);
        },
      },
    ]);
  };

  // Mock function to determine if a note is "Pinned" just for UI presentation (the first item)
  const isPinned = (index) => index === 0 && notes.length > 2;

  const renderNoteItem = ({ item, index }) => {
    const pinned = isPinned(index);

    // Assign random nice colors for the icon bg based on ID so it stays consistent
    const bgHex = [
      "rgba(168,85,247,0.2)",
      "rgba(16,185,129,0.2)",
      "rgba(249,115,22,0.2)",
      "rgba(244,63,94,0.2)",
      "rgba(59,130,246,0.2)",
    ];
    const textColors = [
      { dark: "#c084fc", light: "#a855f7" }, // purple-400 : purple-500
      { dark: "#34d399", light: "#10b981" }, // emerald-400 : emerald-500
      { dark: "#fb923c", light: "#f97316" }, // orange-400 : orange-500
      { dark: "#fb7185", light: "#f43f5e" }, // rose-400 : rose-500
      { dark: "#60a5fa", light: "#3b82f6" }, // blue-400 : blue-500
    ];
    const idx = item.id % 5;

    if (pinned) {
      return (
        <View className="mb-6 px-5">
          <InteractiveCard onPress={() => openEditModal(item)}>
            <View className="bg-emerald-600 dark:bg-emerald-700 rounded-[28px] p-6 shadow-sm shadow-emerald-600/20 relative overflow-hidden">
              <View className="absolute right-0 top-0 opacity-10">
                <Ionicons name="bookmark" size={120} color="white" />
              </View>
              <View className="flex-row justify-between mb-4 mt-2">
                <Text className="text-emerald-100 bg-emerald-500/50 px-3 py-1.5 rounded-full text-[11px] font-bold tracking-widest uppercase">
                  Penting
                </Text>
                <Text className="text-emerald-100/80 text-[11px] font-semibold mt-1">
                  Baru saja
                </Text>
              </View>
              <Text className="text-white text-2xl font-bold font-serif mb-3 leading-snug">
                {item.title}
              </Text>
              <Text
                className="text-emerald-50 font-medium leading-relaxed text-[15px] opacity-90"
                numberOfLines={2}
              >
                {item.content || "Tidak ada pratinjau konten."}
              </Text>
            </View>
          </InteractiveCard>
        </View>
      );
    }

    return (
      <View className="mb-4 px-5">
        <InteractiveCard onPress={() => openEditModal(item)}>
          <View className="bg-white dark:bg-slate-800 rounded-[28px] p-5 shadow-sm shadow-slate-200/50 dark:shadow-none border border-slate-100 dark:border-slate-700">
            <View className="flex-row justify-between items-center mb-4">
              <View className="flex-row items-center">
                <View
                  className="w-10 h-10 rounded-2xl items-center justify-center mr-3 border border-slate-100 dark:border-slate-700/50"
                  style={{ backgroundColor: bgHex[idx] }}
                >
                  <Ionicons
                    name="book"
                    size={18}
                    color={
                      isDark ? textColors[idx].dark : textColors[idx].light
                    }
                  />
                </View>
                <Text className="text-slate-500 dark:text-slate-400 text-xs font-bold uppercase tracking-widest">
                  {item.course_name
                    ? item.course_name.substring(0, 20)
                    : "Catatan Umum"}
                </Text>
              </View>
              <TouchableOpacity
                onPress={() => confirmDelete(item.id)}
                className="bg-slate-50 dark:bg-slate-700/50 p-2 rounded-xl"
              >
                <Ionicons name="trash" size={16} color="#F43F5E" />
              </TouchableOpacity>
            </View>
            <Text className="text-slate-800 dark:text-white text-xl font-bold font-serif mb-2 leading-snug">
              {item.title}
            </Text>
            <Text
              className="text-slate-500 dark:text-slate-400 leading-relaxed text-[15px] font-medium mb-5"
              numberOfLines={2}
            >
              {item.content || "Tidak ada pratinjau konten."}
            </Text>
            <View className="flex-row items-center text-xs pt-3 border-t border-slate-100 dark:border-slate-700/50">
              <Ionicons
                name="time"
                size={14}
                color={isDark ? "#64748B" : "#94A3B8"}
              />
              <Text className="text-slate-500 dark:text-slate-500 text-xs ml-1.5 font-bold mr-4">
                Hari ini
              </Text>
              <Ionicons
                name="document-text"
                size={14}
                color={isDark ? "#64748B" : "#94A3B8"}
              />
              <Text className="text-slate-500 dark:text-slate-500 text-xs ml-1.5 font-bold">
                0 Files
              </Text>
            </View>
          </View>
        </InteractiveCard>
      </View>
    );
  };

  const renderHeader = () => (
    <>
      {/* Header aligned to dashboard */}
      <View className="px-6 pt-6 pb-2 flex-row justify-between items-center mb-2">
        <View className="flex-row items-center">
          <View className="w-10 h-10 bg-indigo-100 dark:bg-indigo-900/50 rounded-2xl items-center justify-center mr-3">
            <Ionicons name="school" size={20} color="#4F46E5" />
          </View>
          <Text className="text-xl font-bold tracking-tight text-slate-800 dark:text-slate-100">
            SmartStudy
          </Text>
        </View>
      </View>

      <View className="px-5 mb-4 mt-2 flex-row justify-between items-end">
        <View className="flex-1 pr-2">
          <Text className="text-sm font-semibold text-emerald-500 dark:text-emerald-400 mb-1 tracking-widest uppercase">
            Jurnal
          </Text>
          <Text className="text-3xl font-serif font-bold text-[#1a365d] dark:text-white mb-2 tracking-tight">
            Catatan
          </Text>
          <Text className="text-slate-500 dark:text-slate-400 text-sm">
            Simpan ide ringkasan dan materi kuliahmu.
          </Text>
        </View>
      </View>

      <View className="px-5 mb-6">
        <InteractiveCard onPress={openAddModal}>
          <View className="bg-emerald-500 dark:bg-emerald-600 rounded-[20px] py-3 flex-row items-center justify-center shadow-md shadow-emerald-500/20">
            <Ionicons name="create" size={22} color="white" />
            <Text className="text-white font-bold text-[15px] ml-2 tracking-wide">
              Tulis Catatan Baru
            </Text>
          </View>
        </InteractiveCard>
      </View>

      {/* Search Bar */}
      <View className="px-5 mb-5">
        <View className="bg-white dark:bg-slate-800 flex-row items-center px-4 py-2 rounded-[16px] border border-slate-100 dark:border-slate-700 shadow-sm shadow-slate-200/50 dark:shadow-none">
          <Ionicons name="search" size={18} color="#94A3B8" />
          <TextInput
            className="flex-1 ml-2 text-slate-800 dark:text-white text-[14px] font-medium"
            placeholder="Cari catatan kuliah..."
            placeholderTextColor="#94A3B8"
            value={searchQuery}
            onChangeText={setSearchQuery}
          />
        </View>
      </View>

      {/* Filter Chips */}
      <View>
        <ScrollView
          horizontal
          showsHorizontalScrollIndicator={false}
          className="px-5 mb-6"
        >
          {filterChips.map((chip) => (
            <TouchableOpacity
              key={chip}
              onPress={() => setActiveChip(chip)}
              className="px-5 py-2.5 rounded-full mr-3 border"
              style={{
                backgroundColor:
                  activeChip === chip ? "#3b82f6" : "transparent",
                borderColor:
                  activeChip === chip
                    ? "#3b82f6"
                    : isDark
                      ? "#334155"
                      : "#cbd5e1",
              }}
            >
              <Text
                className="font-semibold"
                style={{
                  color:
                    activeChip === chip
                      ? "#ffffff"
                      : isDark
                        ? "#cbd5e1"
                        : "#475569",
                }}
              >
                {chip}
              </Text>
            </TouchableOpacity>
          ))}
          <View className="w-10" />
        </ScrollView>
      </View>
    </>
  );

  return (
    <SafeAreaView
      className="flex-1 bg-slate-50 dark:bg-[#0F172A]"
      edges={["top"]}
    >
      {/* Notes List */}
      <FlatList
        data={notes.filter((n) =>
          n.title.toLowerCase().includes(searchQuery.toLowerCase()),
        )}
        keyExtractor={(item) => item.id.toString()}
        renderItem={renderNoteItem}
        ListHeaderComponent={renderHeader}
        contentContainerStyle={{ paddingBottom: 120 }}
        showsVerticalScrollIndicator={false}
        ListEmptyComponent={
          <View className="flex-1 items-center justify-center py-20">
            <Ionicons
              name="document-text-outline"
              size={60}
              color={isDark ? "#334155" : "#CBD5E1"}
              className="mb-4"
            />
            <Text className="text-slate-500 dark:text-slate-400 font-medium text-center">
              Belum ada catatan.
            </Text>
          </View>
        }
      />

      {/* Modal Add/Edit */}
      <Modal visible={isModalVisible} animationType="slide" transparent={true}>
        <View className="flex-1 justify-end bg-slate-900/60">
          <KeyboardAvoidingView
            behavior={Platform.OS === "ios" ? "padding" : "height"}
            className="bg-white dark:bg-[#0F172A] rounded-t-[40px] h-[92%] overflow-hidden"
          >
            {/* Header / Grabber */}
            <View className="items-center pt-3 pb-4 bg-white dark:bg-[#0F172A] z-10 border-b border-slate-100 dark:border-slate-800">
              <View className="w-12 h-1.5 bg-slate-300 dark:bg-slate-700 rounded-full mb-4" />
              <View className="w-full px-6 flex-row justify-between items-center">
                <TouchableOpacity
                  onPress={() => setModalVisible(false)}
                  className="bg-slate-100 dark:bg-slate-800 p-2 rounded-full"
                >
                  <Ionicons
                    name="close"
                    size={24}
                    color={isDark ? "#94A3B8" : "#64748B"}
                  />
                </TouchableOpacity>
                <Text className="text-lg font-bold text-slate-800 dark:text-white">
                  {editingNote ? "Edit Catatan" : "📝 Tulis Catatan"}
                </Text>
                <TouchableOpacity
                  onPress={saveNote}
                  className="bg-blue-500 px-5 py-2 rounded-full"
                >
                  <Text className="text-white font-bold">Simpan</Text>
                </TouchableOpacity>
              </View>
            </View>

            <ScrollView
              showsVerticalScrollIndicator={false}
              contentContainerStyle={{ padding: 24, paddingBottom: 150 }}
              keyboardShouldPersistTaps="handled"
            >
              <TextInput
                className="text-3xl font-extrabold text-slate-800 dark:text-white mb-6"
                placeholder="Judul Catatan..."
                placeholderTextColor={isDark ? "#475569" : "#94A3B8"}
                value={title}
                onChangeText={setTitle}
              />

              <ScrollView
                horizontal
                showsHorizontalScrollIndicator={false}
                className="mb-8"
                style={{ maxHeight: 40 }}
              >
                <TouchableOpacity
                  onPress={() => setCourseId("")}
                  className="px-4 py-2 rounded-xl border mr-2 flex-row items-center"
                  style={{
                    backgroundColor:
                      courseId === ""
                        ? isDark
                          ? "rgba(30, 58, 138, 0.4)"
                          : "#eff6ff"
                        : "transparent",
                    borderColor:
                      courseId === ""
                        ? "#3b82f6"
                        : isDark
                          ? "#334155"
                          : "#e2e8f0",
                  }}
                >
                  <Ionicons
                    name="list"
                    size={14}
                    color={
                      courseId === ""
                        ? "#3B82F6"
                        : isDark
                          ? "#94A3B8"
                          : "#64748B"
                    }
                  />
                  <Text
                    className="text-sm font-medium ml-2"
                    style={{
                      color:
                        courseId === ""
                          ? isDark
                            ? "#60a5fa"
                            : "#2563eb"
                          : isDark
                            ? "#94a3b8"
                            : "#475569",
                    }}
                  >
                    Umum
                  </Text>
                </TouchableOpacity>
                {courses.map((c) => (
                  <TouchableOpacity
                    key={c.id}
                    onPress={() => setCourseId(c.id)}
                    className="px-4 py-2 rounded-xl border mr-2 flex-row items-center"
                    style={{
                      backgroundColor:
                        courseId === c.id
                          ? isDark
                            ? "rgba(30, 58, 138, 0.4)"
                            : "#eff6ff"
                          : "transparent",
                      borderColor:
                        courseId === c.id
                          ? "#3b82f6"
                          : isDark
                            ? "#334155"
                            : "#e2e8f0",
                    }}
                  >
                    <Ionicons
                      name="book"
                      size={14}
                      color={
                        courseId === c.id
                          ? "#3B82F6"
                          : isDark
                            ? "#94A3B8"
                            : "#64748B"
                      }
                    />
                    <Text
                      className="text-sm font-medium ml-2"
                      style={{
                        color:
                          courseId === c.id
                            ? isDark
                              ? "#60a5fa"
                              : "#2563eb"
                            : isDark
                              ? "#94a3b8"
                              : "#475569",
                      }}
                    >
                      {c.course_name}
                    </Text>
                  </TouchableOpacity>
                ))}
              </ScrollView>

              <TextInput
                className="text-lg text-slate-600 dark:text-slate-300 leading-8 min-h-[400px]"
                placeholder="Mulai menulis ide dan materi kuliah di sini..."
                placeholderTextColor={isDark ? "#475569" : "#CBD5E1"}
                multiline
                textAlignVertical="top"
                value={content}
                onChangeText={setContent}
              />
            </ScrollView>
          </KeyboardAvoidingView>
        </View>
      </Modal>
    </SafeAreaView>
  );
}

import React, { useState, useCallback } from "react";
import {
  View,
  Text,
  TouchableOpacity,
  FlatList,
  TextInput,
  Modal,
  Alert,
  KeyboardAvoidingView,
  Platform,
  ScrollView,
} from "react-native";
import { SafeAreaView } from "react-native-safe-area-context";
import { Ionicons } from "@expo/vector-icons";
import { useFocusEffect } from "@react-navigation/native";
import { fetchAll, executeWrite } from "../database/dbHelper";
import { useColorScheme } from "react-native";
import DateTimePicker from "@react-native-community/datetimepicker";
import InteractiveCard from "../components/InteractiveCard";

export default function SchedulesScreen() {
  const [schedules, setSchedules] = useState({});
  const [courses, setCourses] = useState([]);
  const [isModalVisible, setModalVisible] = useState(false);
  const [editingSchedule, setEditingSchedule] = useState(null);

  const colorScheme = useColorScheme();
  const isDark = colorScheme === "dark";

  const daysOfWeek = [
    "Senin",
    "Selasa",
    "Rabu",
    "Kamis",
    "Jumat",
    "Sabtu",
    "Minggu",
  ];

  // Form State
  const [courseId, setCourseId] = useState("");
  const [dayOfWeek, setDayOfWeek] = useState("Senin");
  const [startTime, setStartTime] = useState("");
  const [endTime, setEndTime] = useState("");
  const [room, setRoom] = useState("");
  const [classType, setClassType] = useState("Teori");

  // Time Picker State
  const [showStartPicker, setShowStartPicker] = useState(false);
  const [showEndPicker, setShowEndPicker] = useState(false);
  const [startTimeObj, setStartTimeObj] = useState(new Date());
  const [endTimeObj, setEndTimeObj] = useState(new Date());

  const loadData = async () => {
    try {
      const scheduleData = await fetchAll(
        `SELECT cs.*, c.course_name, c.lecturer_name 
         FROM class_schedules cs 
         JOIN courses c ON cs.course_id = c.id 
         ORDER BY 
          CASE cs.day_of_week 
            WHEN 'Senin' THEN 1 
            WHEN 'Selasa' THEN 2 
            WHEN 'Rabu' THEN 3 
            WHEN 'Kamis' THEN 4 
            WHEN 'Jumat' THEN 5 
            WHEN 'Sabtu' THEN 6 
            WHEN 'Minggu' THEN 7 
          END, 
          cs.start_time ASC`,
      );

      const grouped = {};
      daysOfWeek.forEach((day) => {
        grouped[day] = [];
      });
      scheduleData.forEach((item) => {
        if (grouped[item.day_of_week]) {
          grouped[item.day_of_week].push(item);
        } else {
          grouped[item.day_of_week] = [item];
        }
      });
      setSchedules(grouped);

      const coursesData = await fetchAll(
        "SELECT id, course_name FROM courses ORDER BY course_name ASC",
      );
      setCourses(coursesData);
    } catch (error) {
      console.error("Failed to load schedules:", error);
    }
  };

  useFocusEffect(
    useCallback(() => {
      loadData();
    }, []),
  );

  const parseTimeStr = (timeStr) => {
    if (!timeStr) return new Date();
    const [hours, minutes] = timeStr.split(":");
    const d = new Date();
    d.setHours(parseInt(hours, 10), parseInt(minutes, 10), 0, 0);
    return d;
  };

  const openAddModal = () => {
    setEditingSchedule(null);
    setCourseId("");
    setDayOfWeek("Senin");
    setStartTime("");
    setEndTime("");
    setStartTimeObj(new Date());
    setEndTimeObj(new Date());
    setRoom("");
    setClassType("Teori");
    setModalVisible(true);
  };

  const openEditModal = (schedule) => {
    setEditingSchedule(schedule);
    setCourseId(schedule.course_id);
    setDayOfWeek(schedule.day_of_week);
    setStartTime(schedule.start_time);
    setEndTime(schedule.end_time);
    setStartTimeObj(parseTimeStr(schedule.start_time));
    setEndTimeObj(parseTimeStr(schedule.end_time));
    setRoom(schedule.room || "");
    setClassType(schedule.class_type || "Teori");
    setModalVisible(true);
  };

  const formatTime = (date) => {
    const d = new Date(date);
    const hours = d.getHours().toString().padStart(2, "0");
    const minutes = d.getMinutes().toString().padStart(2, "0");
    return `${hours}:${minutes}`;
  };

  const onStartTimeChange = (event, selectedTime) => {
    setShowStartPicker(false);
    if (selectedTime) {
      setStartTimeObj(selectedTime);
      setStartTime(formatTime(selectedTime));
    }
  };

  const onEndTimeChange = (event, selectedTime) => {
    setShowEndPicker(false);
    if (selectedTime) {
      setEndTimeObj(selectedTime);
      setEndTime(formatTime(selectedTime));
    }
  };

  const saveSchedule = async () => {
    if (!courseId || !startTime || !endTime) {
      Alert.alert(
        "Error",
        "Mata kuliah, jam mulai, dan jam selesai wajib diisi",
      );
      return;
    }

    try {
      if (editingSchedule) {
        await executeWrite(
          "UPDATE class_schedules SET course_id=?, day_of_week=?, start_time=?, end_time=?, room=?, class_type=? WHERE id=?",
          [
            courseId,
            dayOfWeek,
            startTime,
            endTime,
            room,
            classType,
            editingSchedule.id,
          ],
        );
      } else {
        await executeWrite(
          "INSERT INTO class_schedules (course_id, day_of_week, start_time, end_time, room, class_type) VALUES (?, ?, ?, ?, ?, ?)",
          [courseId, dayOfWeek, startTime, endTime, room, classType],
        );
      }
      setModalVisible(false);
      setTimeout(() => {
        loadData();
      }, 100);
    } catch (error) {
      console.error("Failed to save schedule:", error);
      Alert.alert("Error", "Gagal menyimpan jadwal");
    }
  };

  const confirmDelete = (id) => {
    Alert.alert("Hapus Jadwal", "Apakah Anda yakin?", [
      { text: "Batal", style: "cancel" },
      {
        text: "Hapus",
        style: "destructive",
        onPress: async () => {
          await executeWrite("DELETE FROM class_schedules WHERE id = ?", [id]);
          setTimeout(() => {
            loadData();
          }, 100);
        },
      },
    ]);
  };

  const renderGroupedSchedules = () => {
    return daysOfWeek.map((day) => {
      const daySchedules = schedules[day];
      if (!daySchedules || daySchedules.length === 0) return null;

      return (
        <View key={day} className="mb-8">
          <View className="flex-row items-center mb-4">
            <View className="w-10 h-10 bg-indigo-100 dark:bg-indigo-900/50 rounded-2xl items-center justify-center mr-3 border border-indigo-200 dark:border-indigo-800">
              <Ionicons name="calendar" size={18} color="#4F46E5" />
            </View>
            <Text className="text-xl font-bold font-serif text-[#1a365d] dark:text-white flex-1">
              {day}
            </Text>
            <View className="bg-slate-100 dark:bg-slate-800 px-3 py-1.5 rounded-full border border-slate-200 dark:border-slate-700">
              <Text className="text-slate-600 dark:text-slate-300 text-[11px] font-bold uppercase tracking-widest">
                {daySchedules.length} Sesi
              </Text>
            </View>
          </View>

          {daySchedules.map((item, index) => (
            <View key={item.id} className="mb-4">
              <InteractiveCard>
                <View className="bg-white dark:bg-slate-800 rounded-[28px] p-5 shadow-sm shadow-slate-200/50 dark:shadow-none border border-slate-100 dark:border-slate-700 flex-row">
                  <View className="items-center justify-center w-16 mr-4 pr-4 border-r border-slate-100 dark:border-slate-700">
                    <Text className="text-slate-800 dark:text-white font-bold text-base leading-none text-center">
                      {item.start_time}
                    </Text>
                    <Text className="text-emerald-500 dark:text-emerald-400 text-[9px] my-1 font-bold uppercase tracking-widest text-center">
                      sampai
                    </Text>
                    <Text className="text-slate-500 dark:text-slate-400 font-medium text-sm leading-none text-center">
                      {item.end_time}
                    </Text>
                  </View>

                  <View className="flex-1 justify-center">
                    <View className="flex-row justify-between items-start mb-2">
                      <Text className="text-[17px] font-bold text-slate-800 dark:text-slate-100 flex-1 pr-2 leading-snug">
                        {item.course_name}
                      </Text>
                      <View className="flex-row -mt-1 -mr-2 bg-slate-50 dark:bg-slate-700/50 rounded-xl">
                        <TouchableOpacity
                          onPress={() => openEditModal(item)}
                          className="p-2"
                        >
                          <Ionicons
                            name="pencil"
                            size={16}
                            color={isDark ? "#94A3B8" : "#64748B"}
                          />
                        </TouchableOpacity>
                        <TouchableOpacity
                          onPress={() => confirmDelete(item.id)}
                          className="p-2"
                        >
                          <Ionicons name="trash" size={16} color="#F43F5E" />
                        </TouchableOpacity>
                      </View>
                    </View>

                    <View className="flex-row flex-wrap gap-2">
                      <View className="flex-row items-center bg-indigo-50 dark:bg-indigo-500/10 border border-indigo-100 dark:border-indigo-500/20 px-2 py-1 rounded-md">
                        <Ionicons name="business" size={12} color="#4F46E5" />
                        <Text className="text-indigo-600 dark:text-indigo-400 text-[11px] ml-1.5 font-bold">
                          {item.room || "Ruang TBA"}
                        </Text>
                      </View>
                      <View className="flex-row items-center bg-slate-50 dark:bg-slate-700/50 border border-slate-100 dark:border-slate-600 px-2 py-1 rounded-md">
                        <Ionicons name="person" size={12} color="#64748B" />
                        <Text
                          className="text-slate-600 dark:text-slate-300 text-[11px] ml-1.5 font-medium flex-shrink"
                          numberOfLines={1}
                        >
                          {item.lecturer_name || "Tanpa Dosen"}
                        </Text>
                      </View>
                    </View>
                  </View>
                </View>
              </InteractiveCard>
            </View>
          ))}
        </View>
      );
    });
  };

  return (
    <SafeAreaView className="flex-1 bg-slate-50 dark:bg-[#0F172A]">
      {/* Header SmartStudy top */}
      <View className="px-6 pt-6 pb-2 flex-row justify-between items-center mb-2">
        <View className="flex-row items-center">
          <View className="w-10 h-10 bg-indigo-100 dark:bg-indigo-900/50 rounded-2xl items-center justify-center mr-3">
            <Ionicons name="school" size={20} color="#4F46E5" />
          </View>
          <Text className="text-xl font-bold tracking-tight text-slate-800 dark:text-slate-100">
            SmartStudy
          </Text>
        </View>
      </View>

      <ScrollView showsVerticalScrollIndicator={false} className="pt-2">
        {/* Title and Add Button */}
        <View className="px-5 mb-5 mt-4 flex-row justify-between items-end">
          <View className="flex-1 pr-2">
            <Text className="text-sm font-semibold text-indigo-500 dark:text-indigo-400 mb-1 tracking-widest uppercase">
              Kalender
            </Text>
            <Text className="text-3xl font-serif font-bold text-[#1a365d] dark:text-white mb-2 tracking-tight">
              Jadwal Kuliah
            </Text>
            <Text className="text-slate-500 dark:text-slate-400 text-sm">
              Kelola jadwal perkuliahan rutin setiap harinya.
            </Text>
          </View>
        </View>

        <View className="px-5 mb-8">
          <InteractiveCard onPress={openAddModal}>
            <View className="bg-indigo-600 dark:bg-indigo-500 rounded-[24px] py-4 flex-row items-center justify-center shadow-md shadow-indigo-500/20">
              <Ionicons name="add-circle" size={22} color="white" />
              <Text className="text-white font-bold text-[16px] ml-2 tracking-wide">
                Tambah Sesi Kuliah
              </Text>
            </View>
          </InteractiveCard>
        </View>

        {/* List of Schedules */}
        <View className="px-5">
          {Object.keys(schedules).some((day) => schedules[day]?.length > 0) ? (
            renderGroupedSchedules()
          ) : (
            <View className="flex-1 items-center justify-center py-20 mt-10">
              <Ionicons
                name="calendar-outline"
                size={80}
                color={isDark ? "#334155" : "#CBD5E1"}
                className="mb-4"
              />
              <Text className="text-slate-800 dark:text-white text-lg font-bold pb-1">
                Belum Ada Jadwal
              </Text>
              <Text className="text-slate-500 dark:text-slate-400 text-center mt-1">
                Ketuk tombol + di atas untuk menambahkan jadwal.
              </Text>
            </View>
          )}
          <View className="h-24" />
        </View>
      </ScrollView>

      {/* Modal Add/Edit */}
      <Modal visible={isModalVisible} animationType="slide" transparent={true}>
        <View className="flex-1 justify-end bg-slate-900/60">
          <KeyboardAvoidingView
            behavior={Platform.OS === "ios" ? "padding" : "height"}
            className="bg-white dark:bg-[#0F172A] rounded-t-3xl pt-2 pb-8 px-6 h-[90%]"
          >
            <View className="items-center mb-6">
              <View className="w-12 h-1.5 bg-slate-200 dark:bg-slate-700 rounded-full mt-2" />
            </View>

            <View className="flex-row justify-between items-center mb-6">
              <Text className="text-xl font-bold text-slate-800 dark:text-white">
                {editingSchedule ? "Edit Jadwal" : "Tambah Jadwal"}
              </Text>
              <TouchableOpacity
                onPress={() => setModalVisible(false)}
                className="bg-slate-100 dark:bg-slate-800 p-2 rounded-full"
              >
                <Ionicons name="close" size={24} color="#94A3B8" />
              </TouchableOpacity>
            </View>

            <ScrollView
              showsVerticalScrollIndicator={false}
              contentContainerStyle={{ paddingBottom: 100 }}
              keyboardShouldPersistTaps="handled"
            >
              <Text className="text-sm font-semibold text-slate-700 dark:text-slate-300 mb-2 mt-2">
                Pilih Mata Kuliah *
              </Text>
              <ScrollView
                horizontal
                showsHorizontalScrollIndicator={false}
                className="mb-4 h-12"
              >
                {courses.map((c) => (
                  <TouchableOpacity
                    key={c.id}
                    onPress={() => setCourseId(c.id)}
                    className="px-4 py-3 rounded-xl border mr-2 h-11 justify-center align-middle"
                    style={{
                      backgroundColor:
                        courseId === c.id
                          ? isDark
                            ? "rgba(30, 58, 138, 0.3)"
                            : "#eff6ff"
                          : isDark
                            ? "#1E293B"
                            : "#ffffff",
                      borderColor:
                        courseId === c.id
                          ? "#3b82f6"
                          : isDark
                            ? "#1e293b"
                            : "#e2e8f0",
                    }}
                  >
                    <Text
                      style={{
                        color:
                          courseId === c.id
                            ? isDark
                              ? "#60a5fa"
                              : "#1d4ed8"
                            : isDark
                              ? "#94a3b8"
                              : "#475569",
                        fontWeight: courseId === c.id ? "bold" : "normal",
                      }}
                    >
                      {c.course_name}
                    </Text>
                  </TouchableOpacity>
                ))}
                {courses.length === 0 && (
                  <Text className="text-slate-400 py-2">
                    Tambahkan mata kuliah terlebih dahulu.
                  </Text>
                )}
              </ScrollView>

              <Text className="text-sm font-semibold text-slate-700 dark:text-slate-300 mb-2 mt-4">
                Hari *
              </Text>
              <ScrollView
                horizontal
                showsHorizontalScrollIndicator={false}
                className="mb-6 h-12"
              >
                {daysOfWeek.map((day) => (
                  <TouchableOpacity
                    key={day}
                    onPress={() => setDayOfWeek(day)}
                    className="px-4 flex justify-center items-center rounded-xl border mr-2 h-11"
                    style={{
                      backgroundColor:
                        dayOfWeek === day
                          ? isDark
                            ? "rgba(30, 58, 138, 0.3)"
                            : "#eff6ff"
                          : isDark
                            ? "#1E293B"
                            : "#ffffff",
                      borderColor:
                        dayOfWeek === day
                          ? "#3b82f6"
                          : isDark
                            ? "#1e293b"
                            : "#e2e8f0",
                    }}
                  >
                    <Text
                      style={{
                        color:
                          dayOfWeek === day
                            ? isDark
                              ? "#60a5fa"
                              : "#1d4ed8"
                            : isDark
                              ? "#94a3b8"
                              : "#475569",
                        fontWeight: dayOfWeek === day ? "bold" : "normal",
                      }}
                    >
                      {day}
                    </Text>
                  </TouchableOpacity>
                ))}
              </ScrollView>

              <View className="flex-row justify-between mb-6">
                <View className="w-[48%]">
                  <Text className="text-sm font-semibold text-slate-700 dark:text-slate-300 mb-2">
                    Jam Mulai *
                  </Text>
                  <TouchableOpacity
                    onPress={() => setShowStartPicker(true)}
                    className="bg-slate-50 flex-row justify-between items-center dark:bg-[#1E293B] border border-slate-200 dark:border-slate-800 rounded-2xl px-4 py-4"
                  >
                    <Text
                      style={{
                        color: startTime
                          ? isDark
                            ? "#ffffff"
                            : "#1e293b"
                          : isDark
                            ? "#64748b"
                            : "#94a3b8",
                      }}
                    >
                      {startTime ? startTime : "00:00"}
                    </Text>
                    <Ionicons
                      name="time-outline"
                      size={20}
                      color={isDark ? "#64748B" : "#94A3B8"}
                    />
                  </TouchableOpacity>
                  {showStartPicker && (
                    <DateTimePicker
                      value={startTimeObj}
                      mode="time"
                      is24Hour={true}
                      display="default"
                      onChange={onStartTimeChange}
                    />
                  )}
                </View>
                <View className="w-[48%]">
                  <Text className="text-sm font-semibold text-slate-700 dark:text-slate-300 mb-2">
                    Jam Selesai *
                  </Text>
                  <TouchableOpacity
                    onPress={() => setShowEndPicker(true)}
                    className="bg-slate-50 flex-row justify-between items-center dark:bg-[#1E293B] border border-slate-200 dark:border-slate-800 rounded-2xl px-4 py-4"
                  >
                    <Text
                      style={{
                        color: endTime
                          ? isDark
                            ? "#ffffff"
                            : "#1e293b"
                          : isDark
                            ? "#64748b"
                            : "#94a3b8",
                      }}
                    >
                      {endTime ? endTime : "00:00"}
                    </Text>
                    <Ionicons
                      name="time-outline"
                      size={20}
                      color={isDark ? "#64748B" : "#94A3B8"}
                    />
                  </TouchableOpacity>
                  {showEndPicker && (
                    <DateTimePicker
                      value={endTimeObj}
                      mode="time"
                      is24Hour={true}
                      display="default"
                      onChange={onEndTimeChange}
                    />
                  )}
                </View>
              </View>

              <Text className="text-sm font-semibold text-slate-700 dark:text-slate-300 mb-2">
                Ruangan
              </Text>
              <TextInput
                className="bg-slate-50 dark:bg-[#1E293B] border border-slate-200 dark:border-slate-800 rounded-2xl px-4 py-4 text-slate-800 dark:text-white mb-6"
                placeholder="Lab Komputer A"
                placeholderTextColor={isDark ? "#64748B" : "#94A3B8"}
                value={room}
                onChangeText={setRoom}
              />

              <Text className="text-sm font-semibold text-slate-700 dark:text-slate-300 mb-2">
                Jenis Kelas
              </Text>
              <View className="flex-row mb-10 mt-2">
                {["Teori", "Praktikum"].map((type) => (
                  <TouchableOpacity
                    key={type}
                    onPress={() => setClassType(type)}
                    className="flex-1 py-3 items-center border-b-2 justify-center"
                    style={{
                      borderColor:
                        classType === type
                          ? "#3b82f6"
                          : isDark
                            ? "#1e293b"
                            : "#e2e8f0",
                    }}
                  >
                    <Text
                      className="font-bold"
                      style={{
                        color:
                          classType === type
                            ? isDark
                              ? "#60a5fa"
                              : "#3b82f6"
                            : isDark
                              ? "#64748b"
                              : "#94a3b8",
                      }}
                    >
                      {type}
                    </Text>
                  </TouchableOpacity>
                ))}
              </View>

              <TouchableOpacity
                onPress={saveSchedule}
                className="bg-blue-500 rounded-2xl py-4 items-center shadow-lg shadow-blue-500/30 dark:shadow-none"
              >
                <Text className="text-white font-bold text-base">
                  Simpan Jadwal
                </Text>
              </TouchableOpacity>
            </ScrollView>
          </KeyboardAvoidingView>
        </View>
      </Modal>
    </SafeAreaView>
  );
}

import React, { useState, useCallback } from "react";
import {
  View,
  Text,
  TouchableOpacity,
  FlatList,
  TextInput,
  Modal,
  Alert,
  KeyboardAvoidingView,
  Platform,
  ScrollView,
} from "react-native";
import { SafeAreaView } from "react-native-safe-area-context";
import { Ionicons } from "@expo/vector-icons";
import { useFocusEffect } from "@react-navigation/native";
import { fetchAll, executeWrite } from "../database/dbHelper";
import { useColorScheme } from "react-native";
import DateTimePicker, {
  DateTimePickerAndroid,
} from "@react-native-community/datetimepicker";
import InteractiveCard from "../components/InteractiveCard";
import * as Notifications from "expo-notifications";

export default function TasksScreen() {
  const [tasks, setTasks] = useState([]);
  const [courses, setCourses] = useState([]);
  const [isModalVisible, setModalVisible] = useState(false);
  const [editingTask, setEditingTask] = useState(null);

  // Stats
  const [stats, setStats] = useState({
    total: 0,
    belum: 0,
    selesai: 0,
    terlewat: 0,
  });

  const colorScheme = useColorScheme();
  const isDark = colorScheme === "dark";

  // Form State
  const [taskName, setTaskName] = useState("");
  const [courseId, setCourseId] = useState("");
  const [deadline, setDeadline] = useState("");
  const [priority, setPriority] = useState("Sedang");

  // Date Picker State
  const [showPicker, setShowPicker] = useState(false);
  const [dateObj, setDateObj] = useState(new Date());

  const loadData = async () => {
    try {
      let query = `
        SELECT t.*, c.course_name 
        FROM tasks t 
        LEFT JOIN courses c ON t.course_id = c.id 
        ORDER BY t.status DESC, t.deadline ASC
      `;

      const tasksData = await fetchAll(query);
      setTasks(tasksData);

      // Calculate stats
      let total = tasksData.length;
      let selesai = tasksData.filter((t) => t.status === "Selesai").length;
      let belum = total - selesai;
      let terlewat = 0; // Simple mock for testing, ideally checked against current date

      setStats({ total, belum, selesai, terlewat });

      const coursesData = await fetchAll(
        "SELECT id, course_name FROM courses ORDER BY course_name ASC",
      );
      setCourses(coursesData);

      // Sinkronisasi Jadwal Notifikasi Push Lokal secara Latar Belakang (Non-blocking)
      syncNotifications(tasksData).catch(console.error);
    } catch (error) {
      console.error("Failed to load tasks:", error);
    }
  };

  const syncNotifications = async (tasksData) => {
    try {
      await Notifications.cancelAllScheduledNotificationsAsync();

      for (const t of tasksData) {
        if (t.status === "Belum Dikerjakan" && t.deadline) {
          const parts = t.deadline.split(" ");
          if (parts.length === 2) {
            const dateParts = parts[0].split("/");
            const timeParts = parts[1].split(":");
            if (dateParts.length === 3 && timeParts.length === 2) {
              const taskDate = new Date(
                parseInt(dateParts[2], 10),
                parseInt(dateParts[1], 10) - 1,
                parseInt(dateParts[0], 10),
                parseInt(timeParts[0], 10),
                parseInt(timeParts[1], 10),
              );

              const now = new Date();

              const notifyTime1H = new Date(
                taskDate.getTime() - 60 * 60 * 1000,
              );
              if (notifyTime1H > now) {
                await Notifications.scheduleNotificationAsync({
                  content: {
                    title: "⏰ Pengingat Deadline",
                    body: `${t.task_name} harus segera diselesaikan dalam 1 jam!`,
                    sound: true,
                  },
                  trigger: {
                    type: Notifications.SchedulableTriggerInputTypes.DATE,
                    date: notifyTime1H,
                  },
                });
              }

              const notifyTime24H = new Date(
                taskDate.getTime() - 24 * 60 * 60 * 1000,
              );
              if (notifyTime24H > now) {
                await Notifications.scheduleNotificationAsync({
                  content: {
                    title: "📅 Pengingat H-1 Tugas",
                    body: `Jangan lupa kerjakan tugas: ${t.task_name}`,
                    sound: true,
                  },
                  trigger: {
                    type: Notifications.SchedulableTriggerInputTypes.DATE,
                    date: notifyTime24H,
                  },
                });
              }
            }
          }
        }
      }
    } catch (e) {
      console.warn("Failed to sync notifications:", e);
    }
  };

  useFocusEffect(
    useCallback(() => {
      loadData();
    }, []),
  );

  const toggleTaskStatus = async (task) => {
    const newStatus =
      task.status === "Selesai" ? "Belum Dikerjakan" : "Selesai";
    try {
      await executeWrite("UPDATE tasks SET status = ? WHERE id = ?", [
        newStatus,
        task.id,
      ]);
      // Beri waktu SQLite melepas lock sebelum membaca ulang
      setTimeout(() => loadData(), 100);
    } catch (error) {
      console.error("Failed to update status:", error);
    }
  };

  const confirmDelete = (id) => {
    Alert.alert("Hapus Tugas", "Apakah Anda yakin ingin menghapus tugas ini?", [
      { text: "Batal", style: "cancel" },
      {
        text: "Hapus",
        style: "destructive",
        onPress: async () => {
          await executeWrite("DELETE FROM tasks WHERE id = ?", [id]);
          setTimeout(() => loadData(), 100);
        },
      },
    ]);
  };

  const openAddModal = () => {
    setEditingTask(null);
    setTaskName("");
    setCourseId("");
    setDeadline("");
    setDateObj(new Date());
    setPriority("Sedang");
    setModalVisible(true);
  };

  const formatDate = (date) => {
    const d = new Date(date);
    const day = d.getDate().toString().padStart(2, "0");
    const month = (d.getMonth() + 1).toString().padStart(2, "0");
    const year = d.getFullYear();
    const hours = d.getHours().toString().padStart(2, "0");
    const minutes = d.getMinutes().toString().padStart(2, "0");
    return `${day}/${month}/${year} ${hours}:${minutes}`;
  };

  const onDateChange = (event, selectedDate) => {
    // Handling seragam utk pengingkaran picker
    if (Platform.OS === "ios") {
      setShowPicker(false);
    }

    // Tipe "set" menandakan pengguna menekan OK
    if (event.type === "set" && selectedDate) {
      setDateObj(selectedDate);
      // Format 24 Jam khusus tugas:
      setDeadline(formatDate(selectedDate));
    }
  };

  const showAndroidDatePicker = () => {
    DateTimePickerAndroid.open({
      value: dateObj || new Date(),
      onChange: (event, date) => {
        // Tangkap hasil pemilihan tanggal (DatePicker) dulu
        if (event.type === "set" && date) {
          const currentSelectedDate = date;
          // Segera panggil TimePicker untuk jamnya!
          DateTimePickerAndroid.open({
            value: currentSelectedDate,
            mode: "time",
            is24Hour: true,
            onChange: (timeEvent, timeDate) => {
              if (timeEvent.type === "set" && timeDate) {
                const finalDate = new Date(
                  currentSelectedDate.getFullYear(),
                  currentSelectedDate.getMonth(),
                  currentSelectedDate.getDate(),
                  timeDate.getHours(),
                  timeDate.getMinutes(),
                );
                setDateObj(finalDate);
                setDeadline(formatDate(finalDate));
              }
            },
          });
        }
      },
      mode: "date",
      is24Hour: true,
    });
  };

  const saveTask = async () => {
    if (!taskName.trim()) {
      Alert.alert("Error", "Nama tugas tidak boleh kosong");
      return;
    }

    try {
      if (editingTask) {
        await executeWrite(
          "UPDATE tasks SET course_id=?, task_name=?, deadline=?, priority=? WHERE id=?",
          [courseId || null, taskName, deadline, priority, editingTask.id],
        );
      } else {
        await executeWrite(
          "INSERT INTO tasks (course_id, task_name, deadline, priority, status) VALUES (?, ?, ?, ?, ?)",
          [courseId || null, taskName, deadline, priority, "Belum Dikerjakan"],
        );
      }
      setModalVisible(false);
      // Beri napas bagi SQLite sebelum merekam tabel kembali
      setTimeout(() => loadData(), 100);
    } catch (error) {
      console.error("Failed to save task:", error);
      Alert.alert("Error", "Gagal menyimpan tugas");
    }
  };

  const renderTaskItem = ({ item }) => {
    const isCompleted = item.status === "Selesai";

    let priorityStyles = {
      backgroundColor: isDark ? "rgba(59, 130, 246, 0.15)" : "#eff6ff", // blue-50 : blue-500/10
      color: isDark ? "#60A5FA" : "#3b82f6", // blue-400 : blue-500
    };
    let priorityText = "Rendah";

    if (item.priority === "Tinggi") {
      priorityStyles = {
        backgroundColor: isDark ? "rgba(244, 63, 94, 0.15)" : "#fff1f2", // rose-50 : rose-500/10
        color: isDark ? "#FB7185" : "#f43f5e", // rose-400 : rose-500
      };
      priorityText = "Tinggi";
    } else if (item.priority === "Sedang") {
      priorityStyles = {
        backgroundColor: isDark ? "rgba(249, 115, 22, 0.15)" : "#fff7ed", // orange-50 : orange-500/10
        color: isDark ? "#FB923C" : "#f97316", // orange-400 : orange-500
      };
      priorityText = "Sedang";
    }

    return (
      <View className="mb-4">
        <InteractiveCard>
          <View className="bg-white dark:bg-slate-800 rounded-[28px] p-5 shadow-sm shadow-slate-200/50 dark:shadow-none border border-slate-100 dark:border-slate-700 flex-row">
            <TouchableOpacity
              onPress={() => toggleTaskStatus(item)}
              className="w-7 h-7 rounded-[10px] items-center justify-center mr-4 mt-1 shadow-sm border"
              style={{
                backgroundColor: isCompleted
                  ? "#10b981"
                  : isDark
                    ? "#334155"
                    : "#f1f5f9",
                borderColor: isCompleted
                  ? "transparent"
                  : isDark
                    ? "#475569"
                    : "#e2e8f0",
                shadowColor: isCompleted ? "#10b981" : "transparent",
              }}
            >
              {isCompleted && (
                <Ionicons name="checkmark" size={18} color="white" />
              )}
            </TouchableOpacity>

            <View className="flex-1 pr-2">
              <View className="flex-row items-center mb-2">
                {isCompleted ? (
                  <View className="bg-emerald-50 dark:bg-emerald-500/10 border border-emerald-500/20 px-2 py-0.5 rounded mr-2">
                    <Text className="text-[10px] font-bold text-emerald-600 dark:text-emerald-400 uppercase tracking-widest">
                      SELESAI
                    </Text>
                  </View>
                ) : (
                  <View
                    className="px-2 py-0.5 rounded mr-2 border border-slate-200/50 dark:border-transparent"
                    style={{ backgroundColor: priorityStyles.backgroundColor }}
                  >
                    <Text
                      className="text-[10px] font-bold uppercase tracking-widest"
                      style={{ color: priorityStyles.color }}
                    >
                      {priorityText}
                    </Text>
                  </View>
                )}
                <Text className="text-xs text-slate-500 dark:text-slate-400 font-medium">
                  {item.course_name ? item.course_name : "Umum"}
                </Text>
              </View>

              <Text
                className="text-[17px] font-bold leading-snug mb-3 tracking-snug"
                style={{
                  color: isCompleted
                    ? isDark
                      ? "#64748b"
                      : "#94a3b8"
                    : isDark
                      ? "#f1f5f9"
                      : "#1e293b",
                  textDecorationLine: isCompleted ? "line-through" : "none",
                }}
                numberOfLines={2}
              >
                {item.task_name}
              </Text>

              <View className="flex-row justify-between items-center">
                <View className="flex-row items-center">
                  {item.deadline ? (
                    <View className="flex-row items-center mr-3 bg-rose-50 dark:bg-rose-500/10 px-2 py-1 rounded-full">
                      <Ionicons name="time" size={13} color="#F43F5E" />
                      <Text className="text-rose-600 dark:text-rose-400 text-[11px] ml-1.5 font-bold">
                        {item.deadline}
                      </Text>
                    </View>
                  ) : null}
                </View>

                <TouchableOpacity onPress={() => confirmDelete(item.id)}>
                  <Ionicons name="trash-outline" size={18} color="#94A3B8" />
                </TouchableOpacity>
              </View>
            </View>
          </View>
        </InteractiveCard>
      </View>
    );
  };

  return (
    <SafeAreaView className="flex-1 bg-slate-50 dark:bg-[#0F172A]">
      {/* Header SmartStudy top */}
      <View className="px-6 pt-6 pb-2 flex-row justify-between items-center mb-2">
        <View className="flex-row items-center">
          <View className="w-10 h-10 bg-indigo-100 dark:bg-indigo-900/50 rounded-2xl items-center justify-center mr-3">
            <Ionicons name="school" size={20} color="#4F46E5" />
          </View>
          <Text className="text-xl font-bold tracking-tight text-slate-800 dark:text-slate-100">
            SmartStudy
          </Text>
        </View>
      </View>

      <FlatList
        data={tasks}
        keyExtractor={(item) => item.id.toString()}
        renderItem={renderTaskItem}
        contentContainerStyle={{
          paddingHorizontal: 20,
          paddingTop: 10,
          paddingBottom: 150,
        }}
        showsVerticalScrollIndicator={false}
        ListHeaderComponent={
          <>
            {/* Title Section */}
            <View className="mb-5 mt-4">
              <Text className="text-sm font-semibold text-indigo-500 dark:text-indigo-400 mb-1 tracking-widest uppercase">
                Produktivitas
              </Text>
              <Text className="text-3xl font-serif font-bold text-[#1a365d] dark:text-white mb-2 tracking-tight">
                Manajemen Tugas
              </Text>
              <Text className="text-slate-500 dark:text-slate-400 text-sm">
                Pantau tenggat waktu dan status tugasmu.
              </Text>
            </View>

            {/* Add Button Full Width */}
            <View className="mb-8">
              <InteractiveCard onPress={openAddModal}>
                <View className="bg-indigo-600 dark:bg-indigo-500 rounded-[24px] py-4 flex-row items-center justify-center shadow-md shadow-indigo-500/20">
                  <Ionicons name="add-circle" size={22} color="white" />
                  <Text className="text-white font-bold text-[16px] ml-2 tracking-wide">
                    Tambah Tugas Baru
                  </Text>
                </View>
              </InteractiveCard>
            </View>

            {/* Stats Grid */}
            <View className="flex-row flex-wrap justify-between mb-8 gap-y-4">
              <View className="w-[48%]">
                <InteractiveCard>
                  <View className="bg-white dark:bg-slate-800 rounded-[28px] p-5 shadow-sm shadow-slate-200/50 dark:shadow-none border border-slate-100 dark:border-slate-700">
                    <View className="bg-blue-50 dark:bg-blue-900/30 w-10 h-10 rounded-2xl items-center justify-center mb-3">
                      <Ionicons name="albums" size={20} color="#3B82F6" />
                    </View>
                    <Text className="text-[10px] text-slate-500 dark:text-slate-400 font-bold mb-1 uppercase tracking-widest">
                      TOTAL
                    </Text>
                    <Text className="text-3xl font-serif font-bold text-slate-800 dark:text-white">
                      {stats.total}
                    </Text>
                  </View>
                </InteractiveCard>
              </View>

              <View className="w-[48%]">
                <InteractiveCard>
                  <View className="bg-white dark:bg-slate-800 rounded-[28px] p-5 shadow-sm shadow-slate-200/50 dark:shadow-none border border-slate-100 dark:border-slate-700">
                    <View className="bg-indigo-50 dark:bg-indigo-900/30 w-10 h-10 rounded-2xl items-center justify-center mb-3">
                      <Ionicons name="time" size={20} color="#6366F1" />
                    </View>
                    <Text className="text-[10px] text-slate-500 dark:text-slate-400 font-bold mb-1 uppercase tracking-widest">
                      BELUM
                    </Text>
                    <Text className="text-3xl font-serif font-bold text-slate-800 dark:text-white">
                      {stats.belum}
                    </Text>
                  </View>
                </InteractiveCard>
              </View>

              <View className="w-[48%]">
                <InteractiveCard>
                  <View className="bg-white dark:bg-slate-800 rounded-[28px] p-5 shadow-sm shadow-slate-200/50 dark:shadow-none border border-slate-100 dark:border-slate-700">
                    <View className="bg-emerald-50 dark:bg-emerald-900/30 w-10 h-10 rounded-2xl items-center justify-center mb-3">
                      <Ionicons
                        name="checkmark-circle"
                        size={20}
                        color="#10B981"
                      />
                    </View>
                    <Text className="text-[10px] text-slate-500 dark:text-slate-400 font-bold mb-1 uppercase tracking-widest">
                      SELESAI
                    </Text>
                    <Text className="text-3xl font-serif font-bold text-slate-800 dark:text-white">
                      {stats.selesai}
                    </Text>
                  </View>
                </InteractiveCard>
              </View>

              <View className="w-[48%]">
                <InteractiveCard>
                  <View className="bg-white dark:bg-slate-800 rounded-[28px] p-5 shadow-sm shadow-slate-200/50 dark:shadow-none border border-slate-100 dark:border-slate-700">
                    <View className="bg-rose-50 dark:bg-rose-900/30 w-10 h-10 rounded-2xl items-center justify-center mb-3">
                      <Ionicons name="alert-circle" size={20} color="#F43F5E" />
                    </View>
                    <Text className="text-[10px] text-slate-500 dark:text-slate-400 font-bold mb-1 uppercase tracking-widest">
                      TERLEWAT
                    </Text>
                    <Text className="text-3xl font-serif font-bold text-slate-800 dark:text-white">
                      {stats.terlewat}
                    </Text>
                  </View>
                </InteractiveCard>
              </View>
            </View>

            {/* List Header */}
            <View className="flex-row justify-between items-center mb-4 mt-2">
              <Text className="text-xl font-bold text-slate-800 dark:text-white tracking-tight">
                Daftar Tugas
              </Text>
            </View>
          </>
        }
        ListFooterComponent={
          tasks.length > 0 ? (
            <TouchableOpacity className="mt-6 mb-10 py-3 items-center">
              <Text className="text-blue-500 font-medium text-sm">
                Lihat Semua Tugas
              </Text>
            </TouchableOpacity>
          ) : null
        }
        ListEmptyComponent={
          <View className="py-20 flex items-center justify-center">
            <Ionicons
              name="checkbox-outline"
              size={60}
              color={isDark ? "#334155" : "#CBD5E1"}
              className="mb-4"
            />
            <Text className="text-slate-500 dark:text-slate-400 font-medium">
              Yeay, Belum ada tugas!
            </Text>
          </View>
        }
      />

      {/* Modal Add Task */}
      <Modal visible={isModalVisible} animationType="slide" transparent={true}>
        <View className="flex-1 justify-end bg-slate-900/60">
          <KeyboardAvoidingView
            behavior={Platform.OS === "ios" ? "padding" : "height"}
            className="bg-white dark:bg-[#0F172A] rounded-t-3xl pt-2 pb-8 px-6 h-[85%]"
          >
            <View className="items-center mb-6">
              <View className="w-12 h-1.5 bg-slate-200 dark:bg-slate-700 rounded-full mt-2" />
            </View>

            <View className="flex-row justify-between items-center mb-6">
              <Text className="text-xl font-bold text-slate-800 dark:text-white">
                {editingTask ? "Edit Tugas" : "Tambah Tugas"}
              </Text>
              <TouchableOpacity
                onPress={() => setModalVisible(false)}
                className="bg-slate-100 dark:bg-slate-800 p-2 rounded-full"
              >
                <Ionicons name="close" size={24} color="#94A3B8" />
              </TouchableOpacity>
            </View>

            <ScrollView
              showsVerticalScrollIndicator={false}
              contentContainerStyle={{ paddingBottom: 100 }}
              keyboardShouldPersistTaps="handled"
            >
              <Text className="text-sm font-semibold text-slate-700 dark:text-slate-300 mb-2 mt-2">
                Nama Tugas *
              </Text>
              <TextInput
                className="bg-slate-50 dark:bg-[#1E293B] border border-slate-200 dark:border-slate-800 rounded-2xl px-4 py-4 text-slate-800 dark:text-white mb-6"
                placeholder="Contoh: Membuat Makalah"
                placeholderTextColor={isDark ? "#64748B" : "#94A3B8"}
                value={taskName}
                onChangeText={setTaskName}
              />

              <Text className="text-sm font-semibold text-slate-700 dark:text-slate-300 mb-2">
                Pilih Mata Kuliah
              </Text>
              <ScrollView
                horizontal
                showsHorizontalScrollIndicator={false}
                className="mb-6 h-12"
              >
                <TouchableOpacity
                  onPress={() => setCourseId("")}
                  className="px-4 flex justify-center items-center rounded-xl border mr-2 h-11"
                  style={{
                    backgroundColor:
                      courseId === ""
                        ? isDark
                          ? "rgba(30, 58, 138, 0.3)"
                          : "#eff6ff"
                        : isDark
                          ? "#1E293B"
                          : "#ffffff",
                    borderColor:
                      courseId === ""
                        ? "#3b82f6"
                        : isDark
                          ? "#1e293b"
                          : "#e2e8f0",
                  }}
                >
                  <Text
                    style={{
                      color:
                        courseId === ""
                          ? isDark
                            ? "#60a5fa"
                            : "#1d4ed8"
                          : isDark
                            ? "#94a3b8"
                            : "#475569",
                      fontWeight: courseId === "" ? "bold" : "normal",
                    }}
                  >
                    Umum / Tanpa MK
                  </Text>
                </TouchableOpacity>
                {courses.map((c) => (
                  <TouchableOpacity
                    key={c.id}
                    onPress={() => setCourseId(c.id)}
                    className="px-4 flex justify-center items-center rounded-xl border mr-2 h-11"
                    style={{
                      backgroundColor:
                        courseId === c.id
                          ? isDark
                            ? "rgba(30, 58, 138, 0.3)"
                            : "#eff6ff"
                          : isDark
                            ? "#1E293B"
                            : "#ffffff",
                      borderColor:
                        courseId === c.id
                          ? "#3b82f6"
                          : isDark
                            ? "#1e293b"
                            : "#e2e8f0",
                    }}
                  >
                    <Text
                      style={{
                        color:
                          courseId === c.id
                            ? isDark
                              ? "#60a5fa"
                              : "#1d4ed8"
                            : isDark
                              ? "#94a3b8"
                              : "#475569",
                        fontWeight: courseId === c.id ? "bold" : "normal",
                      }}
                    >
                      {c.course_name}
                    </Text>
                  </TouchableOpacity>
                ))}
              </ScrollView>

              <Text className="text-sm font-semibold text-slate-700 dark:text-slate-300 mb-2">
                Deadline / Tenggat Waktu
              </Text>
              <TouchableOpacity
                onPress={() => {
                  if (Platform.OS === "android") {
                    showAndroidDatePicker();
                  } else {
                    setShowPicker(true);
                  }
                }}
                className="bg-slate-50 dark:bg-[#1E293B] border border-slate-200 dark:border-slate-800 rounded-2xl px-4 py-4 mb-6 flex-row justify-between items-center"
              >
                <Text
                  className={
                    deadline
                      ? "text-slate-800 dark:text-white"
                      : "text-slate-400"
                  }
                >
                  {deadline || "Pilih Waktu (Contoh: 12/11/2024 10:00)"}
                </Text>
                <Ionicons name="calendar-outline" size={20} color="#94A3B8" />
              </TouchableOpacity>

              {/* KHUSUS iOS: Munculkan Komponen di dalam Render JSX */}
              {Platform.OS === "ios" && showPicker && (
                <DateTimePicker
                  value={dateObj || new Date()}
                  mode="datetime"
                  display="default"
                  onChange={onDateChange}
                />
              )}

              <Text className="text-sm font-semibold text-slate-700 dark:text-slate-300 mb-2">
                Prioritas
              </Text>
              <View className="flex-row justify-between mb-10 mt-2">
                {["Rendah", "Sedang", "Tinggi"].map((p) => (
                  <TouchableOpacity
                    key={p}
                    onPress={() => setPriority(p)}
                    className="flex-1 py-3 items-center border-b-2 justify-center"
                    style={{
                      borderBottomColor:
                        priority === p
                          ? "#3b82f6"
                          : isDark
                            ? "#1e293b"
                            : "#e2e8f0",
                    }}
                  >
                    <Text
                      className="font-bold"
                      style={{
                        color:
                          priority === p
                            ? isDark
                              ? "#60a5fa"
                              : "#3b82f6"
                            : isDark
                              ? "#64748b"
                              : "#94a3b8",
                      }}
                    >
                      {p}
                    </Text>
                  </TouchableOpacity>
                ))}
              </View>

              <TouchableOpacity
                onPress={saveTask}
                className="bg-blue-500 rounded-2xl py-4 items-center shadow-lg shadow-blue-500/30 dark:shadow-none"
              >
                <Text className="text-white font-bold text-base">
                  Simpan Tugas
                </Text>
              </TouchableOpacity>
            </ScrollView>
          </KeyboardAvoidingView>
        </View>
      </Modal>
    </SafeAreaView>
  );
}

import React from "react";
import { ScheduleWidget } from "./ScheduleWidget";
import { fetchAll } from "../database/dbHelper";

export async function widgetTaskHandler(props) {
  const widgetInfo = props.widgetInfo;

  try {
    // Determine the current day in Indonesian (e.g., "Senin")
    const days = [
      "Minggu",
      "Senin",
      "Selasa",
      "Rabu",
      "Kamis",
      "Jumat",
      "Sabtu",
    ];
    const currentDay = days[new Date().getDay()];

    // Query to get today's active schedules joined with course names
    const query = `
      SELECT cs.*, c.course_name, c.lecturer_name 
      FROM class_schedules cs 
      JOIN courses c ON cs.course_id = c.id 
      WHERE cs.day_of_week = ?
      ORDER BY cs.start_time ASC
    `;

    // Fetch data using the existing dbHelper
    const scheduleData = await fetchAll(query, [currentDay]);

    switch (props.widgetAction) {
      case "WIDGET_ADDED":
      case "WIDGET_UPDATE":
      case "WIDGET_RESIZED":
        props.renderWidget(<ScheduleWidget schedules={scheduleData} />);
        break;

      default:
        break;
    }
  } catch (error) {
    console.error("Widget data fetch error:", error);
    // Render an empty state on failure
    props.renderWidget(<ScheduleWidget schedules={[]} />);
  }
}
